# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api/<path:endpoint>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def api_gateway(endpoint):
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return jsonify({'error': 'Authorization header missing'}), 401
    
    token = auth_header.split(' ')[1] if ' ' in auth_header else auth_header
    
    try:
        decoded_token = jwt.decode(token, options={"verify_signature": False})
    except jwt.DecodeError:
        return jsonify({'error': 'Invalid token'}), 401
    
    user_claims = decoded_token
    forwarded_data = {
        'path': endpoint,
        'method': request.method,
        'user_claims': user_claims
    }
    
    # Here you would typically forward the request to your backend services
    # For development purposes, just return the forwarded data
    return jsonify(forwarded_data), 200

if __name__ == '__main__':
    app.run(debug=True)